// Code node 內也可用 $json / $('Node Name') 跨節點引用
// 這個 Code 示範「複合資料處理」

const user = $('Set: 假資料（巢狀物件 + array）').first().json.user;
const items = $('Set: 假資料（巢狀物件 + array）').first().json.items;

// 處理：算總價、找最貴、安全取 zip
const totalPrice = items.filter(x => x.price).reduce((sum, x) => sum + x.price, 0);
const mostExpensive = items.reduce((max, x) => (x.price ?? 0) > (max.price ?? 0) ? x : max, items[0]);
const zipSafe = user.address?.zip ?? '未填';

return [{
  json: {
    summary: `${user.name}（${user.address.city}，郵遞區號 ${zipSafe}）下單共 ${items.length} 樣商品，總價 ${totalPrice}，最貴的是「${mostExpensive.name}」`,
    totalPrice,
    mostExpensive: mostExpensive.name,
    zipSafe
  }
}];
